  "query_mode": "multi_db",
  "planned_steps": [
    { "step": 1, "action": "query", "database": "kommuner", "purpose": "get drammen municipality geometry" },
    { "step": 2, "action": "query", "database": "flomsoner", "purpose": "get 200-year flood zones intersecting drammen" },
    { "step": 3, "action": "query", "database": "matrikkelenbygning", "purpose": "get buildings in drammen with status FA" },
    { "step": 4, "action": "spatial_join", "database": null, "purpose": "intersect buildings with flood zones" },
    { "step": 5, "action": "sort", "database": null, "purpose": "sort by bygningid ascending" },
    { "step": 6, "action": "limit", "database": null, "purpose": "limit to 10 buildings" }
  ]
}
